import React, { memo } from 'react';
import { useTheme } from '../../hooks/useTheme';
import { useFilter, DATE_RANGES, PLATFORMS } from '../../hooks/useFilter';
import { TabId } from '../../types';
import './Header.css';

// ─── Tab config ────────────────────────────────────────────────────────────

interface TabConfig {
  id: TabId;
  label: string;
  icon?: string;
}

const TABS: TabConfig[] = [
  { id: 'Overview',    label: 'Overview'    },
  { id: 'Traffic',     label: 'Traffic'     },
  { id: 'Conversion',  label: 'Conversion'  },
  { id: 'Operations',  label: 'Operations'  },
  { id: 'AI Insights', label: 'AI Insights', icon: '✦' },
];

// ─── Props ─────────────────────────────────────────────────────────────────

interface HeaderProps {
  activeTab: TabId;
  onTabChange: (tab: TabId) => void;
}

// ─── Component ─────────────────────────────────────────────────────────────

export const Header: React.FC<HeaderProps> = memo(({ activeTab, onTabChange }) => {
  const { theme, toggleTheme } = useTheme();
  const { filters, setDateRange, setPlatform } = useFilter();

  return (
    <header className="app-header">
      {/* ── Left ─────────────────────────────────────────── */}
      <div className="app-header__left">
        <nav className="breadcrumb" aria-label="Breadcrumb">
          <span className="breadcrumb__item">Planning</span>
          <span className="breadcrumb__sep" aria-hidden="true">›</span>
          <span className="breadcrumb__item">Breadcrumbs</span>
          <span className="breadcrumb__sep" aria-hidden="true">›</span>
          <span className="breadcrumb__item breadcrumb__item--active">Breadcrumb</span>
        </nav>

        <nav className="tab-nav" role="tablist" aria-label="Dashboard sections">
          {TABS.map(({ id, label, icon }) => (
            <button
              key={id}
              role="tab"
              aria-selected={activeTab === id}
              className={[
                'tab-nav__btn',
                activeTab === id  ? 'tab-nav__btn--active' : '',
                id === 'AI Insights' ? 'tab-nav__btn--ai' : '',
              ].join(' ').trim()}
              onClick={() => onTabChange(id)}
            >
              {icon && <span className="tab-nav__icon" aria-hidden="true">{icon}</span>}
              {label}
            </button>
          ))}
        </nav>
      </div>

      {/* ── Right ────────────────────────────────────────── */}
      <div className="app-header__right">
        {/* Date range selector */}
        <div className="filter-group">
          <span className="filter-label" aria-label="Selected date range">
            {filters.dateRange.startDate} → {filters.dateRange.endDate}
          </span>
          <select
            className="filter-select"
            value={filters.dateRange.label}
            aria-label="Date range"
            onChange={(e) => {
              const range = DATE_RANGES.find((r) => r.label === e.target.value);
              if (range) setDateRange(range);
            }}
          >
            {DATE_RANGES.map((r) => (
              <option key={r.label} value={r.label}>{r.label}</option>
            ))}
          </select>
        </div>

        {/* Platform selector */}
        <div className="filter-group">
          <select
            className="filter-select"
            value={filters.platform}
            aria-label="Platform"
            onChange={(e) => setPlatform(e.target.value)}
          >
            {PLATFORMS.map((p) => (
              <option key={p}>{p}</option>
            ))}
          </select>
        </div>

        {/* Filter count */}
        <button className="filter-btn" aria-label="5 filters active">
          ⚡ Filters
          <span className="filter-count" aria-hidden="true">5</span>
        </button>

        {/* Theme toggle */}
        <button
          className="theme-toggle"
          onClick={toggleTheme}
          aria-label={`Switch to ${theme === 'light' ? 'dark' : 'light'} mode`}
        >
          {theme === 'light' ? '🌙' : '☀️'}
        </button>
      </div>
    </header>
  );
});

Header.displayName = 'Header';
